To develop a Checkers game using Python, we need to implement the logic for the board, pieces, moves, captures, kinging, and win/draw conditions. Below is the implementation in Python:

```python
# checkers.py

class Board:
    def __init__(self):
        self.board = self.create_board()
        self.current_player = 'R'

    def create_board(self):
        board = [[None for _ in range(8)] for _ in range(8)]
        for row in range(3):
            for col in range((row + 1) % 2, 8, 2):
                board[row][col] = 'r'
        for row in range(5, 8):
            for col in range(row % 2, 8, 2):
                board[row][col] = 'b'
        return board

    def print_board(self):
        for row in self.board:
            print(' '.join(piece or '-' for piece in row))

    def is_valid_move(self, start, end):
        start_row, start_col = start
        end_row, end_col = end
        piece = self.board[start_row][start_col]

        if not piece:
            return False

        if piece.islower() and self.current_player == 'R':
            return False
        if piece.isupper() and self.current_player == 'B':
            return False

        row_diff = abs(start_row - end_row)
        col_diff = abs(start_col - end_col)

        if row_diff != 1 or col_diff not in (1, 2):
            return False

        if col_diff == 1:
            if piece.islower() and start_row > end_row:
                return False
            if piece.isupper() and start_row < end_row:
                return False

        if col_diff == 2:
            jump_piece = self.board[(start_row + end_row) // 2][(start_col + end_col) // 2]
            if not jump_piece or jump_piece.islower() == piece.islower():
                return False

        return True

    def move(self, start, end):
        start_row, start_col = start
        end_row, end_col = end
        piece = self.board[start_row][start_col]

        if not self.is_valid_move(start, end):
            raise ValueError("Invalid move")

        self.board[end_row][end_col] = piece
        self.board[start_row][start_col] = None

        jump_piece = self.board[(start_row + end_row) // 2][(start_col + end_col) // 2]
        if jump_piece:
            self.board[(start_row + end_row) // 2][(start_col + end_col) // 2] = None
            if abs(end_row - start_row) == 2 and (end_row == 0 or end_row == 7):
                piece = piece.upper()

        self.current_player = 'B' if self.current_player == 'R' else 'R'

    def is_game_over(self):
        # Check for valid moves
        for row in range(8):
            for col in range(8):
                if self.board[row][col] and self.is_valid_move((row, col), (row + 1, col - 1)):
                    return False
                if self.board[row][col] and self.is_valid_move((row, col), (row + 1, col + 1)):
                    return False

        # Check for win condition
        red_pieces = sum(row.count('r') for row in self.board)
        black_pieces = sum(row.count('b') for row in self.board)

        if not red_pieces:
            print("Black wins!")
            return True
        elif not black_pieces:
            print("Red wins!")
            return True

        return False


class Game:
    def __init__(self):
        self.board = Board()

    def play(self):
        while not self.board.is_game_over():
            self.board.print_board()
            player = 'R' if self.board.current_player == 'R' else 'B'
            move_from = input(f"{player}'s turn. Enter the move (from-to): ").split('-')
            try:
                start, end = tuple(map(int, move_from[0].strip()), int(move_from[1].strip()))
                self.board.move((start // 8, start % 8), (end // 8, end % 8))
            except ValueError as e:
                print(e)

        self.board.print_board()


if __name__ == "__main__":
    game = Game()
    game.play()
```

### Explanation:

1. **Board Class**:
   - `__init__`: Initializes the board with pieces and sets the current player.
   - `create_board`: Creates an 8x8 board with alternating red ('r') and black ('b') pieces.
   - `print_board`: Prints the current state of the board.
   - `is_valid_move`: Checks if a move from start to end is valid according to the rules of Checkers.
   - `move`: Executes a move, handling jumps and kinging.
   - `is_game_over`: Checks if the game is over by ensuring no valid moves are left or determining a winner.

2. **Game Class**:
   - `__init__`: Initializes the game with an instance of the Board class.
   - `play`: Manages the game loop, taking user input for moves and updating the board state until the game is over.

